def validate(args, output):
    upper, lower, colsum = args[0], args[1], args[2]
    n = len(colsum)
    total = sum(colsum)
    # Check if a solution exists
    if total != upper + lower:
        # No solution is possible
        return output == [] or output == [[],[]]
    # Also check colsum values are all 0,1,2
    for v in colsum:
        if v not in (0, 1, 2):
            return False
    if total != upper + lower:
        return output == [] or output == [[],[]]
    # Count mandatory 2s and 1s
    twos = sum(1 for v in colsum if v == 2)
    ones = sum(1 for v in colsum if v == 1)
    upper_avail = upper - twos
    lower_avail = lower - twos
    if upper_avail < 0 or lower_avail < 0:
        return output == [] or output == [[],[]]
    if upper_avail + lower_avail != ones:
        return output == [] or output == [[],[]]
    # At this point a solution exists; output must be a valid 2-row matrix
    if output == [] or output == [[],[]]:
        return False  # solution exists but empty returned
    if not isinstance(output, list) or len(output) != 2:
        return False
    row0, row1 = output[0], output[1]
    if len(row0) != n or len(row1) != n:
        return False
    r0_sum = 0
    r1_sum = 0
    for j in range(n):
        v0, v1 = row0[j], row1[j]
        if v0 not in (0, 1) or v1 not in (0, 1):
            return False
        r0_sum += v0
        r1_sum += v1
        if v0 + v1 != colsum[j]:
            return False
    return r0_sum == upper and r1_sum == lower

