function validate(args, output) {
    const upper = args[0], lower = args[1], colsum = args[2];
    const n = colsum.length;
    const total = colsum.reduce((a, b) => a + b, 0);
    // Check solvability
    const twos = colsum.filter(v => v === 2).length;
    const ones = colsum.filter(v => v === 1).length;
    const upperAvail = upper - twos;
    const lowerAvail = lower - twos;
    const solvable = (
        total === upper + lower &&
        upperAvail >= 0 &&
        lowerAvail >= 0 &&
        upperAvail + lowerAvail === ones
    );
    const isEmpty = !output || output.length === 0 || (output.length === 2 && output[0].length === 0);
    if (!solvable) return isEmpty;
    if (isEmpty) return false;
    if (!Array.isArray(output) || output.length !== 2) return false;
    const row0 = output[0], row1 = output[1];
    if (row0.length !== n || row1.length !== n) return false;
    let r0sum = 0, r1sum = 0;
    for (let j = 0; j < n; j++) {
        const v0 = row0[j], v1 = row1[j];
        if (v0 !== 0 && v0 !== 1) return false;
        if (v1 !== 0 && v1 !== 1) return false;
        r0sum += v0;
        r1sum += v1;
        if (v0 + v1 !== colsum[j]) return false;
    }
    return r0sum === upper && r1sum === lower;
}

