var reconstructMatrix = function(upper, lower, colsum) {
    const n = colsum.length;
    const row0 = new Array(n).fill(0);
    const row1 = new Array(n).fill(0);
    let u = upper, l = lower;
    for (let j = 0; j < n; j++) {
        if (colsum[j] === 2) {
            row0[j] = 1;
            row1[j] = 1;
            u--;
            l--;
        }
    }
    if (u < 0 || l < 0) return [];
    for (let j = 0; j < n; j++) {
        if (colsum[j] === 1) {
            if (u > 0) {
                row0[j] = 1;
                u--;
            } else {
                row1[j] = 1;
                l--;
            }
        }
    }
    if (u !== 0 || l !== 0) return [];
    return [row0, row1];
};
